const input = $input.all()[0].json;
const results = input.results || [];
const monat = new Date().toLocaleDateString('de-DE', { month: 'long', year: 'numeric' });
const heute = new Date().toLocaleDateString('de-DE');

const posts = results.map(page => {
  const props = page.properties;
  const titel = props?.['Titel']?.title?.[0]?.plain_text || 'Ohne Titel';
  const typ = props?.['Type']?.rich_text?.[0]?.plain_text || '-';
  const saeule = props?.['Säule']?.select?.name || '-';
  const hatTracking = !!props?.['Tracking-Datum']?.date?.start;
  const geplantFuer = props?.['Geplant für']?.date?.start || '';
  return { titel, typ, saeule, hatTracking, geplantFuer };
});

const ohneTracking = posts.filter(p => !p.hatTracking);
const mitTracking = posts.filter(p => p.hatTracking);

console.log(`📋 Vorbereitung: ${posts.length} Posts, ${ohneTracking.length} ohne Tracking`);

const children = [
  { object: 'block', type: 'divider', divider: {} },
  {
    object: 'block', type: 'heading_2',
    heading_2: { rich_text: [{ text: { content: '📋 Review Vorbereitung – ' + monat } }], color: 'blue_background' }
  },
  {
    object: 'block', type: 'callout',
    callout: {
      rich_text: [{ text: { content: ohneTracking.length > 0
        ? `${ohneTracking.length} Posts benötigen noch Tracking-Daten in der Content Pipeline (Impressionen, Likes, DMs etc.). Bitte vor dem letzten Montag eintragen!`
        : 'Alle Posts haben Tracking-Daten – bereit für die Monatsanalyse! ✅'
      }}],
      icon: { emoji: ohneTracking.length > 0 ? '⚠️' : '✅' },
      color: ohneTracking.length > 0 ? 'yellow_background' : 'green_background'
    }
  },
  {
    object: 'block', type: 'heading_3',
    heading_3: { rich_text: [{ text: { content: `⏳ Tracking noch ausstehend (${ohneTracking.length})` } }] }
  },
  ...ohneTracking.map(p => ({
    object: 'block', type: 'to_do',
    to_do: {
      rich_text: [{ text: { content: `${p.titel}  │  ${p.typ}  │  ${p.saeule}${p.geplantFuer ? '  │  ' + p.geplantFuer : ''}` } }],
      checked: false
    }
  })),
  {
    object: 'block', type: 'heading_3',
    heading_3: { rich_text: [{ text: { content: `✅ Tracking vollständig (${mitTracking.length})` } }] }
  },
  ...mitTracking.map(p => ({
    object: 'block', type: 'to_do',
    to_do: {
      rich_text: [{ text: { content: `${p.titel}  │  ${p.typ}  │  ${p.saeule}` } }],
      checked: true
    }
  })),
  {
    object: 'block', type: 'paragraph',
    paragraph: {
      rich_text: [{ text: { content: `Vorbereitung erstellt am ${heute}  ·  Analyse-Workflow läuft automatisch am letzten Montag.` }, annotations: { italic: true, color: 'gray' } }]
    }
  }
];

return [{ json: { children } }];

const results = $('Veröffentlichte Posts laden').first().json.results || [];
const ohneTracking = results.filter(p => !p.properties?.['Tracking-Datum']?.date?.start);
const monat = new Date().toLocaleDateString('de-DE', { month: 'long', year: 'numeric' });
const heute = new Date().toLocaleDateString('de-DE');

console.log(`📧 Sende Vorbereitung-Benachrichtigung: ${results.length} Posts, ${ohneTracking.length} ohne Tracking`);

return [{
  json: {
    to: 'wolfgang.baierl@blboardsolutions.de',
    subject: `[LinkedIn] Review-Vorbereitung ${monat} bereit`,
    body: `<div style="font-family:Arial,sans-serif;max-width:600px">
<h2 style="color:#2c5282">Monatliche LinkedIn-Review-Vorbereitung – ${monat}</h2>
<p>Die Checkliste in deiner Notion Review-Seite wurde aktualisiert.</p>
<table style="border-collapse:collapse;width:100%;margin:16px 0">
  <tr style="background:#ebf4ff">
    <td style="padding:12px;border:1px solid #bee3f8"><strong>Posts veröffentlicht</strong></td>
    <td style="padding:12px;border:1px solid #bee3f8;font-size:1.2em">${results.length}</td>
  </tr>
  <tr style="background:${ohneTracking.length > 0 ? '#fffbeb' : '#f0fff4'}">
    <td style="padding:12px;border:1px solid ${ohneTracking.length > 0 ? '#fbd38d' : '#9ae6b4'}"><strong>Ohne Tracking-Daten</strong></td>
    <td style="padding:12px;border:1px solid ${ohneTracking.length > 0 ? '#fbd38d' : '#9ae6b4'};font-size:1.2em;color:${ohneTracking.length > 0 ? '#c05621' : '#276749'}">${ohneTracking.length === 0 ? '✅ 0' : '⚠️ ' + ohneTracking.length}</td>
  </tr>
</table>
${ohneTracking.length > 0
  ? '<p>Bitte <strong>Tracking-Daten</strong> (Impressionen, Likes, Kommentare, DMs/Leads) bis zum letzten Montag in der Content Pipeline eintragen.</p>'
  : '<p style="color:#276749">Alle Tracking-Daten sind vollständig – bereit für die automatische Analyse am letzten Montag!</p>'
}
<p><a href="https://www.notion.so/Monatliche-LinkedIn-Review-Vorlage-36c47c76280281ea8250d38647dd35cc" style="background:#2c5282;color:#fff;padding:10px 20px;text-decoration:none;border-radius:4px;display:inline-block">→ Zur Review-Seite in Notion</a></p>
<p style="color:#999;font-size:0.8em;margin-top:24px">Erstellt am ${heute} · n8n LinkedIn-Workflow</p>
</div>`
  }
}];

const results = $input.all()[0].json?.results;

if (!results || results.length === 0) {
  console.log('⚠️ Keine Posts mit Tracking-Daten – Claude erstellt generischen Startplan.');
  return [{ json: { posts: [], stats: { gesamt_posts: 0, avg_impressionen: 0, avg_kommentare: 0, avg_likes: 0, gesamt_leads: 0, top_post_impressionen: '', top_post_leads: '' }, nach_saeule: {}, nach_typ: {} } }];
}

const posts = results.map(page => {
  const props = page.properties;
  const getText = p => p?.rich_text?.[0]?.plain_text || p?.title?.[0]?.plain_text || '';
  const getSelect = p => p?.select?.name || '';
  const getNum = p => p?.number || 0;
  const getDate = p => p?.date?.start || '';
  return {
    titel: getText(props['Titel']),
    typ: getText(props['Type']),
    saeule: getSelect(props['Säule']),
    geplant_fuer: getDate(props['Geplant für']),
    kw: getNum(props['KW']),
    hook: getText(props['Hook']),
    impressionen: getNum(props['Impressionen']),
    likes: getNum(props['Likes']),
    kommentare: getNum(props['Kommentare']),
    shares: getNum(props['Shares']),
    profil_aufrufe: getNum(props['Profil-Aufrufe']),
    dms_leads: getNum(props['DMs / Leads']),
    neue_kontakte: getNum(props['Neue Kontakte']),
    tracking_datum: getDate(props['Tracking-Datum'])
  };
});

const avg = (arr, key) => posts.length ? Math.round(arr.reduce((s, p) => s + p[key], 0) / arr.length) : 0;
const stats = {
  gesamt_posts: posts.length,
  avg_impressionen: avg(posts, 'impressionen'),
  avg_kommentare: avg(posts, 'kommentare'),
  avg_likes: avg(posts, 'likes'),
  gesamt_leads: posts.reduce((s, p) => s + p.dms_leads, 0),
  top_post_impressionen: [...posts].sort((a,b) => b.impressionen - a.impressionen)[0]?.titel || '',
  top_post_leads: [...posts].sort((a,b) => b.dms_leads - a.dms_leads)[0]?.titel || ''
};

const groupBy = (key, metricKey) => {
  const g = {};
  posts.forEach(p => {
    if (!g[p[key]]) g[p[key]] = { posts: 0, impressionen: 0, kommentare: 0, leads: 0 };
    g[p[key]].posts++;
    g[p[key]].impressionen += p.impressionen;
    g[p[key]].kommentare += p.kommentare;
    g[p[key]].leads += p.dms_leads;
  });
  return g;
};

console.log(`📊 ${posts.length} Posts mit Tracking für Analyse geladen`);
return [{ json: { posts, stats, nach_saeule: groupBy('saeule'), nach_typ: groupBy('typ') } }];

const rawText = $input.all()[0].json.content?.[0]?.text || '';
if (!rawText) throw new Error('Keine Antwort von Claude.');

let parsed;
try { parsed = JSON.parse(rawText); }
catch(e) {
  const m = rawText.match(/```json\s*([\s\S]*?)\s*```/);
  if (m) { parsed = JSON.parse(m[1]); }
  else {
    const s = rawText.indexOf('{'), e2 = rawText.lastIndexOf('}');
    if (s < 0) throw new Error('Kein JSON in Claude-Antwort.');
    parsed = JSON.parse(rawText.slice(s, e2 + 1));
  }
}

if (!parsed.redaktionsplan?.length) throw new Error('Claude hat kein redaktionsplan-Array zurückgegeben.');

const dryRun = $('Konfiguration (DRY_RUN)').first().json.DRY_RUN;
console.log(`✅ ${parsed.redaktionsplan.length} Posts geplant | DRY_RUN=${dryRun}`);

return parsed.redaktionsplan.map(post => ({ json: { ...post, DRY_RUN: dryRun } }));

const p = $input.first().json;
console.log(`[DRY RUN] "${p.titel}" | ${p.geplant_fuer} | ${p.saeule}`);
return [{ json: { ...p, status: 'dry_run' } }];

// Baut die Analyse + Redaktionsplan als strukturierte Notion-Blocks auf
const claudeResponse = $('Claude: Analyse & Redaktionsplan').first().json.content?.[0]?.text || '{}';
const heute = new Date().toLocaleDateString('de-DE');
const monat = new Date().toLocaleDateString('de-DE', { month: 'long', year: 'numeric' });
const dryRun = $('Konfiguration (DRY_RUN)').first().json.DRY_RUN || false;

let analyse = {}, redaktionsplan = [];
try {
  const s = claudeResponse.indexOf('{'), e = claudeResponse.lastIndexOf('}');
  const parsed = JSON.parse(claudeResponse.slice(s, e + 1));
  analyse = parsed.analyse || {};
  redaktionsplan = parsed.redaktionsplan || [];
} catch(e) { console.log('Parse-Fehler:', e.message); }

const stats = $('Daten aufbereiten').first().json.stats || {};

const postBlocks = redaktionsplan.map((post, i) => ({
  object: 'block', type: 'toggle',
  toggle: {
    rich_text: [{ text: { content: `${i+1}. ${post.geplant_fuer}  │  KW${post.kw}  │  ${post.titel}` }, annotations: { bold: true } }],
    children: [
      { object: 'block', type: 'paragraph', paragraph: { rich_text: [{ text: { content: `📂 ${post.saeule}  ·  ${post.typ}` }, annotations: { color: 'gray' } }] } },
      { object: 'block', type: 'paragraph', paragraph: { rich_text: [{ text: { content: '🎯 Hook: ', annotations: { bold: true } }, type: 'text' }, { text: { content: post.hook || '' }, type: 'text' }] } },
      { object: 'block', type: 'paragraph', paragraph: { rich_text: [{ text: { content: '📝 Inhalt: ', annotations: { bold: true } }, type: 'text' }, { text: { content: post.kern_inhalt || '' }, type: 'text' }] } },
      { object: 'block', type: 'paragraph', paragraph: { rich_text: [{ text: { content: '👉 CTA: ', annotations: { bold: true } }, type: 'text' }, { text: { content: post.cta || '' }, type: 'text' }] } },
      { object: 'block', type: 'paragraph', paragraph: { rich_text: [{ text: { content: `🏷️ ${post.hashtags || ''}  ·  🖼️ ${post.image_prompt || ''}` }, annotations: { color: 'gray' } }] } }
    ]
  }
}));

const children = [
  { object: 'block', type: 'divider', divider: {} },
  {
    object: 'block', type: 'heading_2',
    heading_2: {
      rich_text: [{ text: { content: `📊 Analyse & Redaktionsplan – ${monat}${dryRun ? ' [DRY RUN]' : ''}` } }],
      color: 'green_background'
    }
  },
  {
    object: 'block', type: 'callout',
    callout: {
      rich_text: [{ text: { content: `${stats.gesamt_posts || 0} Posts analysiert  ·  ∅ ${stats.avg_impressionen || 0} Impressionen  ·  ∅ ${stats.avg_likes || 0} Likes  ·  ${stats.gesamt_leads || 0} Leads gesamt` } }],
      icon: { emoji: '📈' }, color: 'blue_background'
    }
  },
  { object: 'block', type: 'heading_3', heading_3: { rich_text: [{ text: { content: '🔍 Top-Erkenntnisse' } }] } },
  ...(analyse.top_erkenntnisse || ['Keine Daten vorhanden']).map(e => ({
    object: 'block', type: 'bulleted_list_item',
    bulleted_list_item: { rich_text: [{ text: { content: e } }] }
  })),
  {
    object: 'block', type: 'paragraph',
    paragraph: { rich_text: [
      { text: { content: 'Beste Säule: ' }, annotations: { bold: true } },
      { text: { content: (analyse.beste_saeule || '-') + '   ' } },
      { text: { content: 'Bester Post-Typ: ' }, annotations: { bold: true } },
      { text: { content: analyse.bester_typ || '-' } }
    ]}
  },
  { object: 'block', type: 'heading_3', heading_3: { rich_text: [{ text: { content: `📅 Neuer Redaktionsplan (${redaktionsplan.length} Posts)` } }] } },
  ...postBlocks,
  {
    object: 'block', type: 'paragraph',
    paragraph: {
      rich_text: [{ text: { content: `Generiert am ${heute}${dryRun ? ' – DRY RUN (Posts nicht in Notion angelegt)' : ' – Posts als „Geplant" in Content Pipeline angelegt.'}` }, annotations: { italic: true, color: 'gray' } }]
    }
  }
];

return [{ json: { children } }];

const stats = $('Daten aufbereiten').first().json.stats || {};
const dryRun = $('Konfiguration (DRY_RUN)').first().json.DRY_RUN;
const jetzt = new Date();
const aktuellerMonat = jetzt.toLocaleDateString('de-DE', { month: 'long', year: 'numeric' });
const naechsterMonat = new Date(jetzt.getFullYear(), jetzt.getMonth() + 1, 1)
  .toLocaleDateString('de-DE', { month: 'long', year: 'numeric' });
const heute = jetzt.toLocaleDateString('de-DE');

console.log(`📧 Sende Analyse-Benachrichtigung: ${stats.gesamt_posts || 0} Posts analysiert, DRY_RUN=${dryRun}`);

return [{
  json: {
    to: 'wolfgang.baierl@blboardsolutions.de',
    subject: `[LinkedIn] Redaktionsplan ${naechsterMonat} generiert${dryRun ? ' [DRY RUN]' : ''}`,
    body: `<div style="font-family:Arial,sans-serif;max-width:600px">
<h2 style="color:#276749">LinkedIn-Redaktionsplan ${naechsterMonat} ist fertig</h2>
${dryRun ? '<div style="background:#fffbeb;border:1px solid #f6e05e;padding:12px;border-radius:4px;margin-bottom:16px"><strong>⚠️ DRY RUN:</strong> Posts wurden NICHT in Notion angelegt.</div>' : ''}
<h3 style="color:#2d3748">Analyse ${aktuellerMonat}</h3>
<table style="border-collapse:collapse;width:100%;margin:12px 0">
  <tr style="background:#f0fff4">
    <td style="padding:10px;border:1px solid #9ae6b4"><strong>Posts analysiert</strong></td>
    <td style="padding:10px;border:1px solid #9ae6b4;font-size:1.1em">${stats.gesamt_posts || 0}</td>
  </tr>
  <tr>
    <td style="padding:10px;border:1px solid #e2e8f0">Ø Impressionen</td>
    <td style="padding:10px;border:1px solid #e2e8f0">${stats.avg_impressionen || 0}</td>
  </tr>
  <tr style="background:#f7fafc">
    <td style="padding:10px;border:1px solid #e2e8f0">Ø Likes</td>
    <td style="padding:10px;border:1px solid #e2e8f0">${stats.avg_likes || 0}</td>
  </tr>
  <tr>
    <td style="padding:10px;border:1px solid #e2e8f0">Ø Kommentare</td>
    <td style="padding:10px;border:1px solid #e2e8f0">${stats.avg_kommentare || 0}</td>
  </tr>
  <tr style="background:#f7fafc">
    <td style="padding:10px;border:1px solid #e2e8f0"><strong>DMs / Leads gesamt</strong></td>
    <td style="padding:10px;border:1px solid #e2e8f0"><strong>${stats.gesamt_leads || 0}</strong></td>
  </tr>
  ${stats.top_post_impressionen ? `<tr><td style="padding:10px;border:1px solid #e2e8f0">Top-Post (Impressionen)</td><td style="padding:10px;border:1px solid #e2e8f0;font-style:italic">${stats.top_post_impressionen}</td></tr>` : ''}
</table>
<p>10 neue Posts wurden ${dryRun ? '<strong>NICHT</strong> ' : ''}als „Geplant" in der Content Pipeline angelegt.</p>
<p><a href="https://www.notion.so/Monatliche-LinkedIn-Review-Vorlage-36c47c76280281ea8250d38647dd35cc" style="background:#276749;color:#fff;padding:10px 20px;text-decoration:none;border-radius:4px;display:inline-block">→ Zur Review-Seite in Notion</a>&nbsp;&nbsp;
<a href="https://www.notion.so/35147c762802803f8311ce87bcce27a5" style="background:#2c5282;color:#fff;padding:10px 20px;text-decoration:none;border-radius:4px;display:inline-block">→ Content Pipeline öffnen</a></p>
<p style="color:#999;font-size:0.8em;margin-top:24px">Generiert am ${heute} · n8n LinkedIn-Workflow</p>
</div>`
  }
}];
